""""
EOF v1 validation code - Exported from evmone unit tests
"""

import pytest
from ethereum_test_tools import EOFTestFiller, EOFException, Opcodes as Op
from ethereum_test_tools.eof.v1 import Container, Section

REFERENCE_SPEC_GIT_PATH = "EIPS/eip-3540.md"
REFERENCE_SPEC_VERSION = "12ca2f0bd2f7380100e154aaaa0995c46cbb2710"

@pytest.mark.parametrize(
    "eof_code,expected_hex_bytecode,exception",
    [
        pytest.param(
              Container(
                name = 'EOFV1_0001',
                sections = [
                    Section.Code(code=Op.CALLF[1] + Op.STOP, max_stack_height=0),
                    Section.Code(code=Op.PUSH1[1] * 1023 + Op.POP * 1023 + Op.RETF, code_outputs=0, max_stack_height=1023),
                    ],
              )
              ,
              "",
              None,
              id="max_stack_height_0"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0002',
                sections = [
                    Section.Code(code=Op.PUSH1[1] * 1023 + Op.POP * 1023 + Op.CALLF[1] + Op.STOP, max_stack_height=1023),
                    Section.Code(code=Op.RETF, code_outputs=0, max_stack_height=0),
                    ],
              )
              ,
              "",
              None,
              id="max_stack_height_1"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0003',
                sections = [
                    Section.Code(code=Op.PUSH1[1] * 1024 + Op.STOP, max_stack_height=1024),
                    ],
              )
              ,
              "",
              EOFException.MAX_STACK_HEIGHT_ABOVE_LIMIT,
              id="max_stack_height_2"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0004',
                sections = [
                    Section.Code(code=Op.PUSH1[1] * 1024 + Op.CALLF[1] + Op.POP * 1024 + Op.STOP, max_stack_height=1024),
                    Section.Code(code=Op.RETF, code_outputs=0, max_stack_height=0),
                    ],
              )
              ,
              "",
              EOFException.MAX_STACK_HEIGHT_ABOVE_LIMIT,
              id="max_stack_height_3"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0005',
                sections = [
                    Section.Code(code=Op.CALLF[1] + Op.STOP, max_stack_height=0),
                    Section.Code(code=Op.PUSH1[1] * 1024 + Op.POP * 1024 + Op.RETF, code_outputs=0, max_stack_height=1023),
                    ],
              )
              ,
              "",
              EOFException.INVALID_MAX_STACK_HEIGHT,
              id="max_stack_height_4"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0006',
                sections = [
                    Section.Code(code=Op.PUSH1[1] * 1024 + Op.CALLF[1] + Op.POP * 1024 + Op.STOP, max_stack_height=1023),
                    Section.Code(code=Op.RETF, code_outputs=0, max_stack_height=0),
                    ],
              )
              ,
              "",
              EOFException.INVALID_MAX_STACK_HEIGHT,
              id="max_stack_height_5"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0007',
                sections = [
                    Section.Code(code=Op.PUSH1[0] + Op.RJUMPI[2] + Op.PUSH1[1] + Op.STOP, max_stack_height=1),
                    ],
              )
              ,
              "ef0001010004020001000804000000008000016000e10002600100",
              None,
              id="max_stack_height_6"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0008',
                sections = [
                    Section.Code(code=Op.PUSH1[0] + Op.RJUMPI[-3] + Op.STOP, max_stack_height=1),
                    ],
              )
              ,
              "ef0001010004020001000604000000008000016000e1fffd00",
              EOFException.STACK_HEIGHT_MISMATCH,
              id="max_stack_height_7"
        ),
        pytest.param(
              Container(
                name = 'EOFV1_0009',
                sections = [
                    Section.Code(code=Op.PUSH1[0] + Op.RJUMPV[-4] + Op.STOP, max_stack_height=1),
                    ],
              )
              ,
              "ef0001010004020001000704000000008000016000e200fffc00",
              EOFException.STACK_HEIGHT_MISMATCH,
              id="max_stack_height_8"
        ),
        
    ]
)

def test_example_valid_invalid(
    eof_test: EOFTestFiller,
    eof_code: Container,
    expected_hex_bytecode: str,
    exception: EOFException | None,
):
    """
    Verify eof container construction and exception
    """
    assert bytes(eof_code) == bytes.fromhex(expected_hex_bytecode)

    eof_test(
        data=eof_code,
        expect_exception=exception,
    )
